INSERT INTO `hz_commitment` (`commitment_id`, `tenant_id`, `project_id`, `commitment_type`, `commitment_content`, `signature_image`, `sign_time`, `ip_address`, `device_info`, `status`, `create_by`, `create_time`, `update_by`, `update_time`, `remark`, `del_flag`)
VALUES
	(1,1,3,'1','<h2 style=\"text-align: center;\"><strong>人才公寓申请承诺书</strong></h2>\n<p><br></p>\n<p>本人郑重承诺：</p>\n<p><br></p>\n<ol>\n  <li><strong>真实信息承诺</strong><br>本人提供的所有申请材料和信息真实、准确、完整，不存在任何虚假、隐瞒或误导性陈述。如有虚假，愿意承担由此产生的一切法律责任和后果。</li>\n  <li><br></li>\n  <li><strong>资格条件承诺</strong><br>本人符合人才公寓申请条件，包括但不限于：学历要求、工作单位要求、社保缴纳要求、住房情况要求等。如条件发生变化不再符合要求，将主动退出。</li>\n  <li><br></li>\n  <li><strong>用途限制承诺</strong><br>承租的人才公寓仅用于本人及家庭成员居住使用，不将房屋用于经营、办公或其他商业用途，不擅自转租、转借、转让或与他人调换使用。</li>\n  <li><br></li>\n  <li><strong>诚信居住承诺</strong><br>入住后将遵守相关管理规定，按时缴纳租金及各项费用，爱护房屋及配套设施，维护小区公共秩序，做文明租户。</li>\n  <li><br></li>\n  <li><strong>动态管理承诺</strong><br>理解并接受人才公寓实行动态管理，同意配合定期资格复审。如本人或家庭成员住房、收入等情况发生变化不再符合保障条件的，将在规定时间内主动退出。</li>\n  <li><br></li>\n  <li><strong>退出机制承诺</strong><br>租赁期满不再续租或因违规被取消资格的，将在规定时间内搬离并办理退房手续，按要求将房屋及设施归还，结清所有费用。</li>\n</ol>\n<p><br></p>\n<p>本人已充分知晓并理解以上承诺内容，愿意严格遵守。如有违反，自愿承担相应责任。</p>\n<p><br></p>\n<p><br></p>\n<p><strong>承诺人签字：</strong>______________</p>\n<p><strong>承诺日期：</strong>______________</p>','data:image/png;base64,','2026-01-15 00:44:07','127.0.0.1','Mozilla/5.0 (iPhone; CPU iPhone OS 18_5 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/18.5 Mobile/15E148 Safari/604.1','0','',NULL,'',NULL,NULL,'0'),
