	(1,'HT20260114134542','1',1,NULL,1,'张三','410123199001011234','13800138000',3,54,'101','郑州航空港区大河路与雍州路交叉口西南角5号楼1单元101',2200.00,2000.00,'2026-01-14','2026-04-14',3,'1',5,0,'<h2><strong>人才公寓租赁合同</strong></h2><p><br></p><p><strong>甲方（出租方）：</strong>港好住管理公司</p><p><strong>乙方（承租方）：</strong>张三</p><p><strong>身份证号：</strong>410123199001011234</p><p><strong>联系电话：</strong>13800138000</p><p><br></p><h3><strong>第一条 租赁房屋基本情况</strong></h3><p>甲方将位于<strong>郑州航空港区大河路与雍州路交叉口西南角5号楼1单元101</strong>的房屋出租给乙方使用。</p><p><br></p><h3><strong>第二条 租赁期限</strong></h3><p>租赁期限自<strong>2026-01-14</strong>起至<strong>2026-04-14</strong>止。</p><p><br></p><h3><strong>第三条 租金及押金</strong></h3><p>1. 月租金为人民币<strong>2200.00</strong>元（大写：<strong>贰仟贰佰元整</strong>）。</p><p>2. 押金为人民币<strong>2000.00</strong>元（大写：<strong>贰仟元整</strong>）。</p><p>3. 乙方应按<u>月</u>支付租金，每月<u>1</u>日前支付当月租金。</p><p><br></p><h3><strong>第四条 房屋使用要求</strong></h3><p>1. 乙方应合理使用并爱护房屋及其附属设施，不得擅自改变房屋结构。</p><p>2. 乙方不得利用房屋从事违法活动。</p><p>3. 乙方应按时缴纳水电费、物业费等相关费用。</p><p><br></p><h3><strong>第五条 违约责任</strong></h3><p>1. 乙方逾期支付租金超过15天的，甲方有权解除合同并收回房屋。</p><p>2. 任何一方违约的，应向对方支付相当于<strong>月租金30%</strong>的违约金。</p><p>3. 因乙方原因造成房屋及设施损坏的，乙方应负责修复或赔偿。</p><p><br></p><h3><strong>第六条 合同解除</strong></h3><p>1. 租赁期满，本合同自动终止。</p><p>2. 乙方需提前退租的，应提前<strong>30天</strong>书面通知甲方。</p><p>3. 合同解除后，甲方应在<strong>7个工作日</strong>内退还押金（扣除应付未付费用及损坏赔偿）。</p><p><br></p><h3><strong>第七条 其他约定</strong></h3><p>1. 本合同一式两份，甲乙双方各执一份，具有同等法律效力。</p><p>2. 本合同未尽事宜，双方协商解决。</p><p>3. 本合同自双方签字或盖章之日起生效。</p><p><br></p><p><br></p><p><strong>甲方（盖章）：</strong>______________        <strong>乙方（签字）：</strong>______________</p><p><strong>签订日期：</strong>______________        <strong>签订日期：</strong>______________</p>',NULL,'/profile/upload/2026/01/14/0c3fd659abe84c39bc014087e22bf474.png',NULL,'2026-01-14 13:45:42','0','0',NULL,'',NULL,'',NULL,NULL,'2'),
